private scheduleManifestWrite(): void {
  this.manifestDirty = true;

  if (this.manifestPendingWrite !== null) return;

  this.manifestPendingWrite = new Promise(resolve => setTimeout(resolve, 250))
    .then(() => this.drainManifest())
    .finally(() => { this.manifestPendingWrite = null; });
}

const ps = this.inflightSets.get(key);
if (ps) await ps.catch(() => undefined);  // yields here

const existing = this.inflightGets.get(key);
if (existing !== undefined) {
  const result = await existing;
  if (result !== undefined) this.hitCount++; else this.missCount++;
  return result;
}

const pending = this.getPersistent(key);
this.inflightGets.set(key, pending);  // may overwrite another caller's pending

async clear(): Promise<void> {
  if (this.initPromise) await this.initPromise.catch(() => undefined);
  this._generation++;
  this.memoryCache.clear();
  this.persistentTracker.clear();
  this.inflightGets.clear();
  this.inflightSets.clear();
  if (this.opts.persistent && this.opts.basePath) {
    try {
      const files = await fs.readdir(this.opts.basePath);
      await Promise.allSettled(
        files.map((file) => fs.unlink(path.join(this.opts.basePath!, file)))
      );
    } catch (e) { ... }
  }
}

const gen = this._generation;
const previous = this.inflightSets.get(key) ?? Promise.resolve();
const pending = (async () => {
  try { await previous; } catch { /* proceed */ }
  if (this._generation !== gen) return;   // only check here
  // ... eviction loop ...
  try {
    const tmp = filePath + `.tmp-${process.pid}-${tmpCounter++}`;
    await fs.writeFile(tmp, Buffer.from(master));
    await fs.rename(tmp, filePath);
    this.persistentTracker.set(name, true, size);  // no gen check here
  } catch (e) { ... }
})();

await this.evictPersistentFraction(0.75);
if (this._generation !== gen) return;  // last gen check
try {
  await this.writePersistentFile(name, buffer);  // async - gen can change here
  if (this._generation !== gen) return;          // this guard IS present - OK
  this.persistentTracker.set(key, { name }, size);
} catch (retryErr) { ... }

while (this.persistentTracker.size + size > this.opts.persistentLimit && this.persistentTracker.count > 0) {
  const oldest = this.persistentTracker.getOldestKey();
  if (oldest === undefined) break;
  this.persistentTracker.delete(oldest);
  this.evictionsCount++;
  await fs.unlink(path.join(this.opts.basePath!, oldest)).catch(() => undefined);
}

if (typeof navigator !== 'undefined' && navigator.locks) {
  await navigator.locks.request('jxl-cache-manifest', async () => performWrite());
} else {
  await performWrite();
}
